-- STEP 1: Create tables

CREATE TABLE IF NOT EXISTS user_account (
  user_id     INT PRIMARY KEY AUTO_INCREMENT,
  username    VARCHAR(100),
  password    VARCHAR(255),
  role        VARCHAR(50)
);

CREATE TABLE IF NOT EXISTS patient (
  patient_id    INT PRIMARY KEY AUTO_INCREMENT,
  user_id       INT,
  full_name     VARCHAR(100),
  nric          VARCHAR(20),
  phone         VARCHAR(20),
  email         VARCHAR(100),
  date_of_birth DATE,
  FOREIGN KEY (user_id) REFERENCES user_account(user_id)
);

CREATE TABLE IF NOT EXISTS medical_staff (
  staff_id        INT PRIMARY KEY AUTO_INCREMENT,
  user_id         INT,
  full_name       VARCHAR(100),
  role            VARCHAR(50),
  department      VARCHAR(100),
  specialisation  VARCHAR(100),
  FOREIGN KEY (user_id) REFERENCES user_account(user_id)
);

CREATE TABLE IF NOT EXISTS web_admin (
  admin_id    INT PRIMARY KEY AUTO_INCREMENT,
  user_id     INT,
  full_name   VARCHAR(100),
  admin_role  VARCHAR(50),
  FOREIGN KEY (user_id) REFERENCES user_account(user_id)
);

CREATE TABLE IF NOT EXISTS appointment (
  appointment_id    INT PRIMARY KEY AUTO_INCREMENT,
  patient_id        INT,
  doctor_id         INT,
  appointment_type  VARCHAR(100),
  appointment_date  DATETIME,
  status            VARCHAR(50),
  FOREIGN KEY (patient_id) REFERENCES patient(patient_id),
  FOREIGN KEY (doctor_id)  REFERENCES medical_staff(staff_id)
);

CREATE TABLE IF NOT EXISTS walk_in_queue (
  queue_id            INT PRIMARY KEY AUTO_INCREMENT,
  patient_id          INT,
  assigned_staff_id   INT,
  managed_by_admin_id INT,
  check_in_time       DATETIME,
  priority_status     VARCHAR(20),
  queue_status        VARCHAR(30),
  FOREIGN KEY (patient_id)          REFERENCES patient(patient_id),
  FOREIGN KEY (assigned_staff_id)   REFERENCES medical_staff(staff_id),
  FOREIGN KEY (managed_by_admin_id) REFERENCES web_admin(admin_id)
);

CREATE TABLE IF NOT EXISTS consultation (
  consultation_id     INT PRIMARY KEY AUTO_INCREMENT,
  appointment_id      INT,
  queue_id            INT,
  patient_id          INT,
  staff_id            INT,
  visit_type          VARCHAR(20),
  service_type        VARCHAR(100),
  temperature         DECIMAL(4,1),
  blood_pressure      VARCHAR(20),
  symptoms            TEXT,
  diagnosis           TEXT,
  prescription_notes  TEXT,
  lab_required        VARCHAR(1) NOT NULL DEFAULT 'N',
  mc_given            INT NOT NULL DEFAULT 0,
  medical_bill        DECIMAL(10,2),
  rating              INT,
  consultation_time   DATETIME,
  FOREIGN KEY (appointment_id) REFERENCES appointment(appointment_id),
  FOREIGN KEY (queue_id)       REFERENCES walk_in_queue(queue_id),
  FOREIGN KEY (patient_id)     REFERENCES patient(patient_id),
  FOREIGN KEY (staff_id)       REFERENCES medical_staff(staff_id)
);

CREATE TABLE IF NOT EXISTS lab_result (
  lab_result_id   INT PRIMARY KEY AUTO_INCREMENT,
  consultation_id INT,
  test_type       VARCHAR(50),
  result_details  TEXT,
  result_date     DATETIME,
  result_status   VARCHAR(20),
  FOREIGN KEY (consultation_id) REFERENCES consultation(consultation_id)
);

